if (scenario.command === "claim") {
  const policyItemTypes = new Set<string>(items.map((item) => item.type));
  const damages: { type: string }[] = scenario.damages ?? [];
  for (const damage of damages) {
    if (!policyItemTypes.has(damage.type)) {
      failWith(`damage type ${damage.type} not in the policy`);
    }
  }
  const policyCounts = new Map<string, number>();
  for (const item of items) {
    policyCounts.set(item.type, (policyCounts.get(item.type) ?? 0) + 1);
  }
  const damageCounts = new Map<string, number>();
  for (const damage of damages) {
    damageCounts.set(damage.type, (damageCounts.get(damage.type) ?? 0) + 1);
  }
  for (const [type, count] of damageCounts) {
    if (count > (policyCounts.get(type) ?? 0)) {
      failWith(`more damage entries of type ${type} than the policy covers`);
    }
  }
}
